var e=JSON.parse(`[{"id":"L2_1","type":"narration","speaker":null,"text":{"KOREA":"성찬을 준비하라. 새로운 날이 당도하리니.","JPN":"聖餐を準備しろ。新しい日が到来する。","ENG":"Prepare the feast. A new dawn is coming.","TWN":"預備盛宴吧。新天已來到。"},"stage":{"bg":"AB_UI_NKM_UI_CUTSCEN_BG_FIRE","slots":{"L":null,"C":null,"R":null}}},{"id":"L3_1","type":"narration","speaker":null,"text":{"KOREA":"불완전한 지식, 불완전한 존재들이 성찬을 통해 하나가 되어, 완전해질 것이다.","JPN":"不完全な知識、不完全な存在たちが聖餐により一つになり、完全体となる。","ENG":"The feast will complete the imperfect knowledge and perfect the imperfect beings.","TWN":"不完整的知識，不完整的存在將透過盛宴合而為一，變得完整。"},"stage":{"bg":"AB_UI_NKM_UI_CUTSCEN_BG_FIRE","slots":{"L":null,"C":null,"R":null}}},{"id":"L4_1","type":"narration","speaker":null,"text":{"KOREA":"모두 지식의 성찬을 준비하라.\\n모두 연회를 시작하라.","JPN":"みんな、知識の聖餐を準備しろ。\\nみんな、宴会を始めろ。","ENG":"[[","TWN":"大家準備知識的盛宴吧，\\n大家開始宴會吧。"},"stage":{"bg":"AB_UI_NKM_UI_CUTSCEN_BG_FIRE","slots":{"L":null,"C":null,"R":null}}},{"id":"L5_1","type":"narration","speaker":null,"text":{"KOREA":"오랜 갈구와 허기의 끝이 마침내 도래했다.","JPN":"長い渇きと飢えの果てが、ついに訪れたのだ。","ENG":"[[","TWN":"長久的渴望與饑餓終於到達了盡頭。"},"stage":{"bg":"AB_UI_NKM_UI_CUTSCEN_BG_FIRE","slots":{"L":null,"C":null,"R":null}}},{"id":"L6_1","type":"narration","speaker":null,"text":{"KOREA":"오늘의 성찬은 어린 양의 피와 살일지니.\\n삼키는 자가 삼켜지고, 삼켜지는 자가 삼키리라.","JPN":"今日は子羊の血と肉が聖餐となり、\\n飲み込む者が飲み込まれ、飲み込まれる者が飲み込むことになるだろう。","ENG":"When shall the banquet begin?","TWN":"今天的盛宴，是羔羊的血和肉。\\n吞食者將被吞噬，被吞噬者將去吞食。"},"stage":{"bg":"AB_UI_NKM_UI_CUTSCEN_BG_FIRE","slots":{"L":null,"C":null,"R":null}}},{"id":"L7_1","type":"narration","speaker":null,"text":{"KOREA":"연회는 아직인가.","JPN":"宴会はまだか。","ENG":"The long thirst and hunger are finally coming to an end.","TWN":"宴會還沒開始嗎？"},"stage":{"bg":"AB_UI_NKM_UI_CUTSCEN_BG_FIRE","slots":{"L":null,"C":null,"R":null}}},{"id":"L8_1","type":"narration","speaker":null,"text":{"KOREA":"성찬의 주인이 도착했다. 어머니께서 도래하였다.","JPN":"聖餐の主が到着した。お母さんのお出ましだ。","ENG":"The host of the feast has arrived. Mother has arrived.","TWN":"盛宴的主人到了，母親到了。"},"stage":{"bg":"AB_UI_NKM_UI_CUTSCEN_BG_FIRE","slots":{"L":null,"C":null,"R":null}}},{"id":"L11_1","type":"dialog","speaker":"ANNE_PRYDWEN_NPC_QM","text":{"KOREA":"……이브!","JPN":"……イヴ！","ENG":"...Eve!","TWN":"……伊芙！"},"stage":{"bg":"BLACK","slots":{"L":null,"C":null,"R":null}}},{"id":"L17_1","type":"dialog","speaker":"ANNE_PRYDWEN_NPC_QM","text":{"KOREA":"야, 너 괜찮아? 왜 그렇게 식은 땀을 많이 흘려?","JPN":"ちょっと、あなた大丈夫？　すごい冷や汗だよ？","ENG":"Hey, are you okay? Why are you sweating so much?","TWN":"喂，你沒事吧？你怎麼出那麼多冷汗？"},"stage":{"bg":"DORMITORY_3","slots":{"L":null,"C":{"char_id":"ANNE_PRYDWEN_NPC_QM","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"EVE_PRYDWEN_NPC_NULL","text":{"KOREA":"으음……. 앤?","JPN":"ううん……アン？","ENG":"Mm... Ann?","TWN":"嗯嗯……安妮？"},"stage":{"bg":"DORMITORY_3","slots":{"L":null,"C":{"char_id":"ANNE_PRYDWEN_NPC_QM","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"ANNE_PRYDWEN_NPC_NULL","text":{"KOREA":"또 그 이상한 꿈을 꾼 거야?","JPN":"またあの変な夢をみたの？","ENG":"Did you have that weird dream again?","TWN":"又做了那個奇怪的夢嗎？"},"stage":{"bg":"DORMITORY_3","slots":{"L":null,"C":{"char_id":"ANNE_PRYDWEN_NPC_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"ANNE_PRYDWEN_NPC_NULL","text":{"KOREA":"<color=#ffd34c>정신감응</color>이라고 했던가? 너도 참 성가시겠다, 그거.","JPN":"<color=#ffd34c>テレパシー</color>だっけ？　あなたも大変だね。","ENG":"<color=#ffd34c>Telepathy</color>, was it? Seems like a real hassle.","TWN":"<color=#ffd34c>精神感應</color>是吧？那個能力也太煩人了吧。"},"stage":{"bg":"DORMITORY_3","slots":{"L":null,"C":{"char_id":"ANNE_PRYDWEN_NPC_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"ANNE_PRYDWEN_NPC_NULL","text":{"KOREA":"매일매일 그런 꿈을 꾸는데 대체 잠은 어떻게 자냐?","JPN":"毎日そんな夢を見るなんて、ちゃんと眠れてるの？","ENG":"How can you sleep when you have dreams like that every day?","TWN":"每天都做那樣的夢，到底怎麼睡覺啊？"},"stage":{"bg":"DORMITORY_3","slots":{"L":null,"C":{"char_id":"ANNE_PRYDWEN_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"EVE_PRYDWEN_NPC_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"DORMITORY_3","slots":{"L":null,"C":{"char_id":"EVE_PRYDWEN_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"ANNE_PRYDWEN_NPC_NULL","text":{"KOREA":"너무 걱정하지 마. 수녀님도 괜찮을 거라고 했잖아.","JPN":"そんなに心配しないで。シスターも大丈夫って言ってたし。","ENG":"Don't worry. Even Sister Theodora said that it was going to be all right.","TWN":"不過也別太擔心，修女也說過會沒事的。"},"stage":{"bg":"DORMITORY_3","slots":{"L":{"char_id":"EVE_PRYDWEN_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ANNE_PRYDWEN_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L29_1","type":"dialog","speaker":"EVE_PRYDWEN_NPC_NULL","text":{"KOREA":"응, 고마워 앤.","JPN":"うん、ありがとう。アン。","ENG":"Yeah. Thanks, Ann.","TWN":"嗯，謝謝你，安妮。"},"stage":{"bg":"DORMITORY_3","slots":{"L":{"char_id":"EVE_PRYDWEN_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ANNE_PRYDWEN_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L31_1","type":"dialog","speaker":"ANNE_PRYDWEN_NPC_NULL","text":{"KOREA":"서두르자. 또 테스트를 땡땡이 쳤다간, 우리 둘 다 닭장 청소 당번이라고!","JPN":"急ごう。またテストをサボったら、二人ともニワトリ小屋の掃除当番になっちゃう！","ENG":"Let's hurry. If we miss another test, we'll have to clean out the chicken pen!","TWN":"快點吧，如果再不去參加測驗，我們二個就要打掃雞舍了！"},"stage":{"bg":"DORMITORY_3","slots":{"L":null,"C":{"char_id":"ANNE_PRYDWEN_NPC_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"ANNE_PRYDWEN_NPC_NULL","text":{"KOREA":"이제 닭똥이라면 지긋지긋해! 물론 닭고기 스튜는 좋아하지만.","JPN":"もうニワトリの糞は勘弁！　チキンのシチューは好きだけどね。","ENG":"I'm so sick of chicken poop! But I still do like chicken stew.","TWN":"我現在看到雞屎就覺得煩！不過我還是很喜歡燉雞的。"},"stage":{"bg":"DORMITORY_3","slots":{"L":null,"C":{"char_id":"ANNE_PRYDWEN_NPC_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"EVE_PRYDWEN_NPC_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"DORMITORY_3","slots":{"L":{"char_id":"EVE_PRYDWEN_NPC_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"ANNE_PRYDWEN_NPC_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L36_1","type":"dialog","speaker":"ANNE_PRYDWEN_NPC_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"DORMITORY_3","slots":{"L":{"char_id":"EVE_PRYDWEN_NPC_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"ANNE_PRYDWEN_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L38_1","type":"dialog","speaker":"ANNE_PRYDWEN_NPC_NULL","text":{"KOREA":"히! 히! 히! 힛! 드디어 만났구나! 가면 카운터! 나는 괴인 999호 간질간지럼!","JPN":"ヒ・ヒ・ヒ・ヒッ！　やっと出会ったな！　仮面カウンター！　オレは怪人999号、クスグリマン！","ENG":"He! He! He! He! We finally met! Masked Counter! I am Monster No. 999, Tickle-tickle!","TWN":"嘿！嘿！嘿！嘿！終於見面了！蒙面制裁者！我是999號怪人，癢癢！"},"stage":{"bg":"DORMITORY_3","slots":{"L":null,"C":{"char_id":"ANNE_PRYDWEN_NPC_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"EVE_PRYDWEN_NPC_NULL","text":{"KOREA":"간질간지럼? 그런 괴인은 없잖아?","JPN":"クスグリマン？　そんな怪人聞いたことないけど？","ENG":"Tickle-tickle? There's no monster named that!","TWN":"癢癢嗎？沒有那樣的怪人吧？"},"stage":{"bg":"DORMITORY_3","slots":{"L":{"char_id":"EVE_PRYDWEN_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ANNE_PRYDWEN_NPC_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L42_1","type":"dialog","speaker":"ANNE_PRYDWEN_NPC_NULL","text":{"KOREA":"눈치 없긴! 대충 있다고 쳐!","JPN":"ちょっと、少しは空気を呼んでよ！","ENG":"C'mon! Just roll with it!","TWN":"真是不識趣！你就當是有吧！"},"stage":{"bg":"DORMITORY_3","slots":{"L":{"char_id":"EVE_PRYDWEN_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ANNE_PRYDWEN_NPC_NULL","face":"UNIT_HATE"}}}},{"id":"L44_1","type":"dialog","speaker":"ANNE_PRYDWEN_NPC_NULL","text":{"KOREA":"아무튼! 이 몸은 웃지 않는 못된 아이들을 혼쭐내는 정의의 괴인이다!","JPN":"とにかく！　オレ様は笑わない悪い子どもたちにぎゃふんと言わせる正義の怪人だ！","ENG":"Anyway! I am the monster of justice who comes to punish naughty children who don't laugh!","TWN":"總之！我是教訓不愛笑的壞孩子的正義魔人！"},"stage":{"bg":"DORMITORY_3","slots":{"L":null,"C":{"char_id":"ANNE_PRYDWEN_NPC_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L45_1","type":"dialog","speaker":"ANNE_PRYDWEN_NPC_NULL","text":{"KOREA":"내 공격을 받아낼 수 있을까!","JPN":"オレの攻撃を受け止められるかな？","ENG":"Will you be able to withstand my attack?!","TWN":"來試試抵擋我的攻擊吧！"},"stage":{"bg":"DORMITORY_3","slots":{"L":null,"C":{"char_id":"ANNE_PRYDWEN_NPC_NULL","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};